import{_ as n,c as a,a as i,o as e}from"./app-CEcM0piI.js";const p={};function l(t,s){return e(),a("div",null,s[0]||(s[0]=[i(`<p>底层是使用动态代理</p><h1 id="概述" tabindex="-1"><a class="header-anchor" href="#概述"><span>概述</span></a></h1><p>AOP（Aspect Oriented Programming）是一种设计思想，是软件设计领域中的面向切面编程，它是面向对象编程的一种补充和完善，它以通过预编译方式和运行期动态代理方式实现，在不修改源代码的情况下，给程序动态统添加额外功能的一种技术。利用AOP可以对业务逻辑的各个部分进行隔离，从而使得业务逻辑各部分之间的耦合度降低，提高程序的可重用性，同时提高了开发的效率。</p><p>其实就是面向特定方法编程</p><p>动态代理是面向切面编程最主流的实现。而SpringAOP是Spring框架的高级技术，旨在管理bean对象的过程中，主要通过底层的动态代理机制，对特定的方法进行编程。</p><h3 id="横切关注点" tabindex="-1"><a class="header-anchor" href="#横切关注点"><span>横切关注点</span></a></h3><p>分散在每个各个模块中解决同一样的问题，如用户验证、日志管理、事务处理、数据缓存都属于横切关注点。</p><p>从每个方法中抽取出来的同一类非核心业务。在同一个项目中，我们可以使用多个横切关注点对相关方法进行多个不同方面的增强。</p><p>这个概念不是语法层面的，而是根据附加功能的逻辑上的需要：有十个附加功能，就有十个横切关注点。</p><h3 id="通知-增强" tabindex="-1"><a class="header-anchor" href="#通知-增强"><span>通知(增强)</span></a></h3><p><strong>Advice，指哪些重复的逻辑，也就是共性功能（最终体现为一个方法）</strong></p><p>增强，通俗说，就是你想要增强的功能，比如安全，事物，日志等。</p><p>每一个横切关注点上要做的事情都需要写一个方法来实现，这样的方法就叫<strong>通知方法</strong>。</p><ul><li>前置通知：在被代理的目标方法前执行</li><li>返回通知：在被代理的目标方法成功结束后执行（寿终正寝）</li><li>异常通知：在被代理的目标方法异常结束后执行（死于非命）</li><li>后置通知：在被代理的目标方法最终结束后执行（盖棺定论）</li><li>环绕通知：使用try...catch...finally结构围绕整个被代理的目标方法，包括上面四种通知对应的所有位置</li></ul><h3 id="切面" tabindex="-1"><a class="header-anchor" href="#切面"><span>切面</span></a></h3><p><strong>Aspect，描述通知与切入点的对应关系（通知+切入点）</strong></p><p>封装通知方法的类 也叫切面类</p><h3 id="目标" tabindex="-1"><a class="header-anchor" href="#目标"><span>目标</span></a></h3><p><strong>Target，通知所应用的对象</strong></p><p>被代理的目标对象</p><h3 id="代理" tabindex="-1"><a class="header-anchor" href="#代理"><span>代理</span></a></h3><p>向目标对象应用通知之后创建的代理对象</p><h3 id="连接点" tabindex="-1"><a class="header-anchor" href="#连接点"><span>连接点</span></a></h3><p><strong>连接点：JoinPoint，可以被AOP控制的方法（暗含方法执行时的相关信息）</strong></p><p>这也是一个纯逻辑概念，不是语法定义的。</p><p>把方法排成一排，每一个横切位置看成x轴方向，把方法从上到下执行的顺序看成y轴，x轴和y轴的交叉点就是连接点。通俗说，就是spring允许你使用通知的地方</p><h3 id="切入点" tabindex="-1"><a class="header-anchor" href="#切入点"><span>切入点</span></a></h3><p><strong>切入点：PointCut，匹配连接点的条件，通知仅会在切入点方法执行时被应用</strong></p><p>定位连接点的方式。</p><p>每个类的方法中都包含多个连接点，所以连接点是类中客观存在的事物（从逻辑上来说）。</p><p>如果把连接点看作数据库中的记录，那么切入点就是查询记录的SQL语句。</p><p>Spring的AOP技术可以通过切入点定位到特定的连接点。通俗说，要实际去增强的方法</p><p>切点通过 org.springframework.aop.Pointcut 接口进行描述，它使用类和方法作为连接点的查询条件。</p><h2 id="动态代理分类" tabindex="-1"><a class="header-anchor" href="#动态代理分类"><span>动态代理分类</span></a></h2><p>动态代理分类：JDK动态代理和cglib动态代理</p><p>有接口的情况使用jdk的动态代理 代理对象和目标对象实现同样的接口</p><p>没有接口的情况使用的是cglib动态代理 通过<strong>继承被代理的目标类（认干爹模式）实现代理，所以不需要目标类实现接口</strong>。</p><p>Aspect：是AOP思想的一种实现。本质上是静态代理，将代理逻辑&quot;织入&quot;被代理的目标类编译得到的字节码文件，所以最终效果是动态的。weaver就是织入器。Spring只是借用了Aspect中的注解</p><p>需要引入依赖</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>		&lt;dependency&gt;</span></span>
<span class="line"><span>			&lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;</span></span>
<span class="line"><span>			&lt;artifactId&gt;spring-boot-starter-aop&lt;/artifactId&gt;</span></span>
<span class="line"><span>		&lt;/dependency&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>开启aspectj自动代理,为目标对象生成代理</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;aop:aspectj-autoaopxy&gt;&lt;/aop:aspectj-autoproxy&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在需要aop的方法上加上@Aspect注解,表示当前类是一个aop类.并在里面使用@Around注解指明要作用到哪些方法上</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@Slf4j</span></span>
<span class="line"><span>@Component</span></span>
<span class="line"><span>@Aspect</span></span>
<span class="line"><span>public class TimeAspect {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @Around(&quot;execution(* com.itheima.service.*.*(..))&quot;)//作用在com.itheima.service包下的所有方法上</span></span>
<span class="line"><span>  public Object recordTime(ProceedingJoinPoint joinPoint) throws Throwable{</span></span>
<span class="line"><span>    //记录开始时间</span></span>
<span class="line"><span>    Long begin=System.currentTimeMillis();</span></span>
<span class="line"><span>    //执行目标方法</span></span>
<span class="line"><span>    Object result=joinPoint.proceed();</span></span>
<span class="line"><span>    //记录结束时间</span></span>
<span class="line"><span>    Long end=System.currentTimeMillis();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    log.info(joinPoint.getSignature()+&quot;耗时: {}ms&quot;,end-begin);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    return result;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>当com.itheima.service包中的所有方法调用时都会执行此切片方法记录耗时</p><h1 id="通知类型" tabindex="-1"><a class="header-anchor" href="#通知类型"><span>通知类型</span></a></h1><table><thead><tr><th>通知</th><th>说明</th></tr></thead><tbody><tr><td>@Around</td><td>环绕通知，此注解标注的通知方法在目标方法前、后都被执行</td></tr><tr><td>@Before</td><td>前置通知，此注解标注的通知方法在目标方法前被执行</td></tr><tr><td>@After</td><td>后置通知，此注解标注的通知方法在目标方法后被执行，无论是否有异常都会执行</td></tr><tr><td>@AfterReturning</td><td>返回后通知，此注解标注的通知方法在目标方法后被执行，有异常不会执行</td></tr><tr><td>@AfterThrowing</td><td>异常后通知，此注解标注的通知方法发生异常后执行</td></tr></tbody></table><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@Slf4j</span></span>
<span class="line"><span>@Component</span></span>
<span class="line"><span>@Aspect</span></span>
<span class="line"><span>public class MyAspect {</span></span>
<span class="line"><span>  @Before(&quot;execution(* com.itheima.service.impl.DeptServiceImpl.*(..))&quot;)</span></span>
<span class="line"><span>  public void before() {</span></span>
<span class="line"><span>    log.debug(&quot;before...&quot;);</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @Around(&quot;execution(* com.itheima.service.impl.DeptServiceImpl.*(..))&quot;)</span></span>
<span class="line"><span>  public Object around(ProceedingJoinPoint pjp) throws Throwable {</span></span>
<span class="line"><span>    log.debug(&quot;around before...&quot;);</span></span>
<span class="line"><span>    Object ret = pjp.proceed();</span></span>
<span class="line"><span>    log.debug(&quot;around after...&quot;);</span></span>
<span class="line"><span>    return ret;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @After(&quot;execution(* com.itheima.service.impl.DeptServiceImpl.*(..))&quot;)</span></span>
<span class="line"><span>  public void after() {</span></span>
<span class="line"><span>    log.debug(&quot;after...&quot;);</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @AfterReturning(&quot;execution(* com.itheima.service.impl.DeptServiceImpl.*(..))&quot;)</span></span>
<span class="line"><span>  public void afterReturning() {</span></span>
<span class="line"><span>    log.debug(&quot;afterReturning...&quot;);</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @AfterThrowing(&quot;execution(* com.itheima.service.impl.DeptServiceImpl.*(..))&quot;)</span></span>
<span class="line"><span>  public void afterThrowing() {</span></span>
<span class="line"><span>    log.debug(&quot;afterThrowing...&quot;);</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>@Around环绕通知需要自己调用FProceedingJoinPoint.roceed(）来让原始方法执行，其他通知不需要考虑目标方法执行 @Around环绕通知方法的返回值，必须指定为object，来接收原始方法的返回值。</p><p>对于监控同一个包下的切入点表达式太过冗余,可以定义切点来引入</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@Slf4j</span></span>
<span class="line"><span>@Component</span></span>
<span class="line"><span>@Aspect</span></span>
<span class="line"><span>public class MyAspect {</span></span>
<span class="line"><span>  @Pointcut(&quot;execution(*com.itheima.service.impl.DeptServiceImpl.*(..))&quot;)</span></span>
<span class="line"><span>  private void pt(){}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @Before(&quot;pt&quot;)</span></span>
<span class="line"><span>  public void before() {}</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>  @Around(&quot;pt&quot;)</span></span>
<span class="line"><span>  public Object around(ProceedingJoinPoint pjp) throws Throwable {}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>对一个空函数上面加上@Pointcut注解写上切入点表达式后就可以直接在通知注解里使用这个空函数名作为切入点表达式的引用了 这样的切入点也可以在其他类中引用,其作用范围受权限修饰符的限制</p><h2 id="通知顺序" tabindex="-1"><a class="header-anchor" href="#通知顺序"><span>通知顺序</span></a></h2><p>当有多个切面的切入点都匹配到了目标方法，目标方法运行时，多个通知方法都会被执行。 不同切面类中，默认按照切面类的类名字母排序：</p><ul><li>目标方法前的通知方法：字母排名靠前的先执行</li><li>目标方法后的通知方法：字母排名靠前的后执际</li></ul><p>用@Order(数字）加在切面类上来控制顺序</p><ul><li>目标方法前的通知方法：数字小的先执行</li><li>目标方法后的通知方法：数字小的后执行</li></ul><h2 id="切入点表达式" tabindex="-1"><a class="header-anchor" href="#切入点表达式"><span>切入点表达式</span></a></h2><p>切入点表达式：描述切入点方法的一种表达式 作用：主要用来决定项目中的哪些方法需要加入通知</p><p>常见形式：</p><ol><li>execution(...) : 根据方法的签名来匹配</li><li>@annotation(...) : 根据注解匹配</li></ol><h3 id="execution" tabindex="-1"><a class="header-anchor" href="#execution"><span>execution</span></a></h3><p>execution主要根据方法的返回值、包名、类名、方法名、方法参数等信息来匹配，语法为：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>execution(访问修饰符? 返回值 包名.类名.?方法名(方法参数) throws 异常?)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>其中带?的表示可以省略的部分 异常：是指方法上声明抛出的异常，不是实际抛出的异常</p><p><strong>可以使用通配符描述切入点</strong></p><ul><li><ul><li>: 单个独立的任意符号，可以通配任意返回值、包名、类名、方法名、任意类型的一个参数，也可以通配包、类、方法名的一部分</li></ul></li><li>** : 多个连续的任意符号，可以通配任意层级的包，或任意类型、任意个数的参数</li></ul><p>书写建议</p><ul><li>所有业务方法名在命名时尽量规范，方便切入点表达式快速匹配。如：查询类方法都是find 开头，更新类方法都是update开头。</li><li>描述切入点方法通常基于接口描述，而不是直接描述实现类，增强拓展性。</li><li>在满足业务需要的前提下，尽量缩小切入点的匹配范围。如：包名匹配尽量不使用.，使用＊匹配单个包。</li></ul><h3 id="annotation" tabindex="-1"><a class="header-anchor" href="#annotation"><span>@annotation</span></a></h3><p>@annotation切入点表达式，用于匹配标识有特定注解的方法</p><h3 id="连接点-1" tabindex="-1"><a class="header-anchor" href="#连接点-1"><span>连接点</span></a></h3><p>在Spring中用JoinPoint抽象了连接点，用它可以获得方法执行时的相关信息，如目标类名、方法名、方法参数等。</p><p>对于@Around通知，获取连接点信息只能使用ProceedingJoinPoint 对于其他四种通知，获取连接点信息只能使用JoinPoint，它是ProceedingJoinPoint的父类型</p>`,74)]))}const r=n(p,[["render",l]]),c=JSON.parse('{"path":"/back/springboot/5/","title":"5 面向切片AOP","lang":"zh-CN","frontmatter":{"title":"5 面向切片AOP","createTime":"2025/06/18 20:59:38","permalink":"/back/springboot/5/"},"readingTime":{"minutes":7.85,"words":2356},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/后端/Spring Boot/5 面向切片AOP.md","headers":[]}');export{r as comp,c as data};
